from pathlib import Path
import re
p=Path('app.js');s=p.read_text(encoding='utf-8')
s=s.replace("guided:{shineAnswers:{},shineCompleted:false,routineChoices:[],medicalProfile:[],dietSetup:{completed:false,answers:{}},pendingMedical:[],confirmedMedical:[]}","guided:{shineAnswers:{},shineCompleted:false,routineChoices:[],medicalProfile:[],doctorIntake:{completed:false,age:'',gender:'',conditions:[],heightCm:'',weightKg:'',deficiencies:[],bmi:null},dietSetup:{completed:false,answers:{}},pendingMedical:[],confirmedMedical:[]}")
s=s.replace("medicalProfile:Array.isArray(parsed.guided?.medicalProfile)?parsed.guided.medicalProfile:[],dietSetup:","medicalProfile:Array.isArray(parsed.guided?.medicalProfile)?parsed.guided.medicalProfile:[],doctorIntake:{...base.guided.doctorIntake,...(parsed.guided?.doctorIntake||{}),conditions:Array.isArray(parsed.guided?.doctorIntake?.conditions)?parsed.guided.doctorIntake.conditions:[],deficiencies:Array.isArray(parsed.guided?.doctorIntake?.deficiencies)?parsed.guided.doctorIntake.deficiencies:[]},dietSetup:")
new=r'''function doctorIntakeData(){return profile().guided.doctorIntake||defaultProfile().guided.doctorIntake}
function calculateBmi(h,w){h=Number(h)/100;w=Number(w);return h>0&&w>0?Math.round(w/(h*h)*10)/10:null}
function renderDoctorWelcome(){return `<div class="screen doctor-welcome-screen"><section class="doctor-welcome"><div class="doctor-symbol">✚</div><p class="eyebrow">DR</p><h1>Know your health picture</h1><p>A clear profile helps organize the education and questions most relevant to you.</p><div class="doctor-points"><span>AGE</span><span>PMH</span><span>BMI</span><span>LABS</span></div><button class="doctor-start" data-open-doctor-intake="1">Build my health profile <b>→</b></button><small>Saved only on this device</small></section></div>`}
function renderMedicalProfile(){document.body.classList.remove('dr-intro-active');setActive('dr');const a=doctorIntakeData(),b=calculateBmi(a.heightCm,a.weightKg),c=(x,y)=>x.includes(y)?'checked':'';app.innerHTML=`<div class="screen doctor-intake-screen"><section class="doctor-intake">${renderBackControl('#/dr','DR','dr')}<header><p class="eyebrow">YOUR HEALTH PROFILE</p><h1>Let’s build your doctor page</h1><p>Enter what you know. You can update this later.</p></header><form id="doctor-intake-form">
<section><h2>1. About you</h2><div class="doctor-fields"><label>Age<input id="doctor-age" type="number" min="1" max="120" value="${esc(a.age)}" required></label><label>Gender<select id="doctor-gender" required><option value="">Choose</option><option value="female" ${a.gender==='female'?'selected':''}>Female</option><option value="male" ${a.gender==='male'?'selected':''}>Male</option><option value="other" ${a.gender==='other'?'selected':''}>Other</option><option value="prefer-not" ${a.gender==='prefer-not'?'selected':''}>Prefer not to say</option></select></label></div></section>
<section><h2>2. Past medical history</h2><p>Choose diagnosed chronic conditions that apply.</p><div class="doctor-choices"><label><input type="checkbox" data-doctor-condition="diabetes" ${c(a.conditions,'diabetes')}><span><b>DM</b>Diabetes</span></label><label><input type="checkbox" data-doctor-condition="hypertension" ${c(a.conditions,'hypertension')}><span><b>HTN</b>High blood pressure</span></label><label><input type="checkbox" data-doctor-condition="dyslipidemia" ${c(a.conditions,'dyslipidemia')}><span><b>DLP</b>High cholesterol</span></label><label><input type="checkbox" data-doctor-condition="asthma" ${c(a.conditions,'asthma')}><span><b>ASTHMA</b>Asthma</span></label></div></section>
<section><h2>3. Height, weight and BMI</h2><div class="doctor-fields"><label>Height (cm)<input id="doctor-height" type="number" min="80" max="250" step="0.1" value="${esc(a.heightCm)}" required></label><label>Weight (kg)<input id="doctor-weight" type="number" min="20" max="400" step="0.1" value="${esc(a.weightKg)}" required></label></div><output id="doctor-bmi"><span>Your BMI</span><strong>${b??'—'}</strong><small>Calculation only; discuss interpretation with your clinician.</small></output></section>
<section><h2>4. Known vitamin or mineral deficiencies</h2><p>Select only deficiencies you were told you have.</p><div class="doctor-choices"><label><input type="checkbox" data-doctor-deficiency="b12" ${c(a.deficiencies,'b12')}><span><b>B12</b>Vitamin B12</span></label><label><input type="checkbox" data-doctor-deficiency="d3" ${c(a.deficiencies,'d3')}><span><b>D3</b>Vitamin D</span></label><label><input type="checkbox" data-doctor-deficiency="iron" ${c(a.deficiencies,'iron')}><span><b>Fe</b>Iron</span></label></div></section>
<div class="doctor-actions"><button type="button" class="btn ghost" data-doctor-cancel="1">Back</button><button class="btn dr" type="submit">Save my health profile</button></div></form></section></div>`}'''
s,n=re.subn(r"function renderMedicalProfile\(\)\{.*?\n\}",new,s,count=1,flags=re.S)
if n!=1: raise SystemExit('profile render not found')
s=s.replace("function renderProgressiveDr(){\n  const c=progressiveConfig().medical,p=profile(),pending=p.guided.pendingMedical||[],confirmed=p.guided.confirmedMedical||[];","function renderProgressiveDr(){\n  const c=progressiveConfig().medical,p=profile(),pending=p.guided.pendingMedical||[],confirmed=p.guided.confirmedMedical||[];\n  if(p.guided.doctorIntake?.completed!==true)return renderDoctorWelcome();")
s=s.replace("function renderDr(){\n  setActive('dr');\n  app.innerHTML=renderProgressiveDr();\n}","function renderDr(){setActive('dr');const first=profile().guided.doctorIntake?.completed!==true;document.body.classList.toggle('dr-intro-active',first);app.innerHTML=renderProgressiveDr()}")
s=s.replace("  if(e.target.closest('[data-open-medical-profile]')){location.hash='#/dr/profile';return}","  if(e.target.closest('[data-open-doctor-intake]')){location.hash='#/dr/profile';return}\n  if(e.target.closest('[data-doctor-cancel]')){location.hash='#/dr';return}\n  if(e.target.closest('[data-open-medical-profile]')){location.hash='#/dr/profile';return}")
anchor="document.addEventListener('click',e=>{"
code="""document.addEventListener('submit',e=>{if(e.target.id!=='doctor-intake-form')return;e.preventDefault();const age=document.getElementById('doctor-age').value,gender=document.getElementById('doctor-gender').value,heightCm=document.getElementById('doctor-height').value,weightKg=document.getElementById('doctor-weight').value,bmi=calculateBmi(heightCm,weightKg);if(!age||!gender||!bmi){showToast('Complete age, gender, height, and weight');return}const conditions=[...document.querySelectorAll('[data-doctor-condition]:checked')].map(x=>x.dataset.doctorCondition),deficiencies=[...document.querySelectorAll('[data-doctor-deficiency]:checked')].map(x=>x.dataset.doctorDeficiency),p=profile();p.guided.doctorIntake={completed:true,age,gender,conditions,heightCm,weightKg,deficiencies,bmi};p.guided.medicalProfile=[...new Set([...(p.guided.medicalProfile||[]),...conditions])];if(deficiencies.includes('iron')&&!(p.guided.confirmedMedical||[]).includes('iron-deficiency'))p.guided.pendingMedical=[...new Set([...(p.guided.pendingMedical||[]),'iron-deficiency'])];saveProfile(p);document.body.classList.remove('dr-intro-active');location.hash='#/dr'});\ndocument.addEventListener('input',e=>{if(!['doctor-height','doctor-weight'].includes(e.target.id))return;const o=document.getElementById('doctor-bmi');if(o)o.querySelector('strong').textContent=calculateBmi(document.getElementById('doctor-height').value,document.getElementById('doctor-weight').value)??'—'});\n\n"""
if "doctor-intake-form')return" not in s:s=s.replace(anchor,code+anchor,1)
p.write_text(s,encoding='utf-8')

p=Path('styles.css');s=p.read_text(encoding='utf-8');s+='''\n\n/* DR focused onboarding and health profile */\nbody.dr-intro-active{overflow:hidden}body.dr-intro-active .bottom-nav{display:none}body.dr-intro-active .app{padding-bottom:0}.doctor-welcome-screen{padding:8px;background:#062b53}.doctor-welcome{min-height:calc(100svh - 16px);display:grid;place-items:center;align-content:center;gap:18px;padding:32px;text-align:center;border-radius:34px;color:#fff;background:radial-gradient(circle at 50% 28%,#218fd055,transparent 28%),linear-gradient(145deg,#061d38,#0b548f 65%,#052746);box-shadow:inset 0 0 0 9px #ffffff08}.doctor-symbol{display:grid;place-items:center;width:104px;height:104px;border-radius:32px;background:#ffffff18;color:#91d8ff;font-size:3rem;box-shadow:0 18px 42px #00162d88}.doctor-welcome h1{max-width:680px;margin:0;font-size:clamp(2.6rem,10vw,5.5rem);line-height:.94;letter-spacing:-.06em}.doctor-welcome>p:not(.eyebrow){max-width:560px;margin:0;color:#d4edfc;font-size:1.08rem;line-height:1.55}.doctor-points{display:flex;gap:12px;flex-wrap:wrap;justify-content:center}.doctor-points span{display:grid;place-items:center;width:70px;height:70px;border:1px solid #9ddaff55;border-radius:22px;background:#042f58aa;font-size:.72rem;font-weight:950}.doctor-start{display:flex;align-items:center;justify-content:space-between;width:min(100%,620px);min-height:72px;padding:15px 18px 15px 26px;border:1px solid #ffffff88;border-radius:999px;background:linear-gradient(135deg,#1476c4,#2aa8ee);color:#fff;font:inherit;font-size:1.2rem;font-weight:900;cursor:pointer}.doctor-start b{display:grid;place-items:center;width:42px;height:42px;border-radius:50%;background:#ffffff22}.doctor-welcome small{color:#a9ddfa}.doctor-intake-screen{max-width:850px;margin:auto}.doctor-intake{display:grid;gap:14px}.doctor-intake>header{padding:24px;border-radius:28px;background:linear-gradient(135deg,#0f4f87,#197dbd);color:#fff}.doctor-intake>header h1{margin:.2rem 0;font-size:clamp(2rem,7vw,3.5rem);letter-spacing:-.05em}.doctor-intake>header p{margin:0;color:#d8efff}.doctor-intake form{display:grid;gap:14px}.doctor-intake form>section{padding:20px;border:1px solid #d6e6f3;border-radius:23px;background:#fff;box-shadow:0 9px 26px #123b5c0d}.doctor-intake h2{margin:0 0 8px}.doctor-intake section>p{margin:.2rem 0 14px;color:#667085}.doctor-fields,.doctor-choices{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px}.doctor-fields label{display:grid;gap:7px;font-weight:850;color:#294b66}.doctor-fields input,.doctor-fields select{min-height:50px;padding:11px;border:1px solid #c9dce9;border-radius:14px;background:#fbfdff;font:inherit}.doctor-choices label{position:relative}.doctor-choices input{position:absolute;opacity:0}.doctor-choices span{display:flex;align-items:center;gap:10px;min-height:58px;padding:10px 12px;border:1px solid #d5e5f1;border-radius:16px;background:#fbfdff;font-weight:800;cursor:pointer}.doctor-choices b{display:grid;place-items:center;min-width:52px;height:36px;padding:0 7px;border-radius:11px;background:#e7f4fe;color:#1768a8;font-size:.72rem}.doctor-choices input:checked+span{border-color:#1976b8;background:#eaf6ff;box-shadow:0 0 0 2px #1976b822}.doctor-choices input:focus-visible+span{outline:3px solid #1767a8;outline-offset:2px}#doctor-bmi{display:grid;grid-template-columns:auto auto;align-items:center;gap:2px 12px;margin-top:14px;padding:14px 16px;border-radius:18px;background:linear-gradient(135deg,#0d568f,#1884c8);color:#fff}#doctor-bmi strong{grid-row:1/3;grid-column:2;font-size:2.2rem}#doctor-bmi small{color:#d8efff}.doctor-actions{display:flex;justify-content:flex-end;gap:10px;padding-bottom:24px}@media(max-width:600px){.doctor-welcome{border-radius:27px;padding:20px}.doctor-points span{width:60px;height:60px}.doctor-fields,.doctor-choices{grid-template-columns:1fr}.doctor-intake form>section{padding:16px}.doctor-actions{display:grid;grid-template-columns:1fr}.doctor-actions .btn{width:100%}}@media(prefers-reduced-motion:no-preference){.doctor-symbol{animation:doctorFloat 4s ease-in-out infinite}.doctor-points span{animation:doctorNode 3.8s ease-in-out infinite}}@keyframes doctorFloat{50%{transform:translateY(-7px)}}@keyframes doctorNode{50%{transform:translateY(-5px)}}\n''';p.write_text(s,encoding='utf-8')

p=Path('docs/HISTORY.md');s=p.read_text(encoding='utf-8');s+='''\n\n### DR health-profile onboarding\n\n- Added a focused blue DR welcome and a local profile form for age, gender, selected chronic conditions, height, weight, BMI, and known B12, vitamin D, or iron deficiency.\n- BMI is displayed as a calculation only without diagnosis or category interpretation.\n- Iron deficiency continues through explicit confirmation; no dosing, treatment selection, or laboratory interpretation was added.\n''';p.write_text(s,encoding='utf-8')